const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const STATE_FILE = path.join(PROJECT, '.claude/em-pipeline-state.json');

const { execSync } = require('child_process');
let initialCommit = '';
try {
  initialCommit = execSync('git rev-parse HEAD', { cwd: PROJECT }).toString().trim();
} catch {}

let state;
try {
  state = JSON.parse(fs.readFileSync(STATE_FILE, 'utf8'));
} catch {
  state = {
    phases: {
      'preflight': { status: 'pending', attempts: 0, result: null },
      'cad-import': { status: 'pending', attempts: 0, result: null },
      'mesh-gen': { status: 'pending', attempts: 0, result: null },
      'mom-solver': { status: 'pending', attempts: 0, result: null },
      'fdtd-python': { status: 'pending', attempts: 0, result: null },
      'frontend': { status: 'pending', attempts: 0, result: null },
      'tests': { status: 'pending', attempts: 0, result: null },
    },
    currentPhase: 'preflight',
    startedAt: new Date().toISOString(),
    maxRetries: 3,
    initialCommit,
  };
}

// Determine next phase to run
const phaseOrder = ['preflight', 'cad-import', 'mesh-gen', 'mom-solver', 'fdtd-python', 'frontend', 'tests'];
const parallelPhases = { 'mom-solver': 'fdtd-python' }; // these run in parallel

let nextPhase = null;
for (const phase of phaseOrder) {
  if (state.phases[phase].status !== 'complete') {
    nextPhase = phase;
    break;
  }
}

state.currentPhase = nextPhase;
fs.writeFileSync(STATE_FILE, JSON.stringify(state, null, 2));

return [{ json: { state, nextPhase } }];

const { execSync } = require('child_process');
const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const checks = {};

try { execSync('cd src-tauri && cargo check 2>&1', { cwd: PROJECT, timeout: 180000 }); checks.cargo = 'OK'; }
catch (e) { checks.cargo = 'FAIL: ' + (e.stdout?.toString().slice(0, 200) || e.message); }

try { execSync('npx tsc --noEmit 2>&1', { cwd: PROJECT, timeout: 60000 }); checks.tsc = 'OK'; }
catch (e) { checks.tsc = 'FAIL: ' + (e.stdout?.toString().slice(0, 200) || e.message); }

try { execSync('python3 --version 2>&1', { cwd: PROJECT }); checks.python = 'OK'; }
catch (e) { checks.python = 'FAIL'; }

try {
  const status = execSync('git status --porcelain', { cwd: PROJECT }).toString();
  checks.git = status.trim() === '' ? 'CLEAN' : 'DIRTY: ' + status.slice(0, 200);
} catch (e) { checks.git = 'FAIL'; }

const critical = ['cargo', 'tsc', 'python'].every(k => checks[k] === 'OK');
return [{ json: { checks, status: critical ? 'complete' : 'failed', phase: 'preflight' } }];

const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const STATE_FILE = path.join(PROJECT, '.claude/em-pipeline-state.json');
const state = JSON.parse(fs.readFileSync(STATE_FILE, 'utf8'));
const phase = state.currentPhase;

// Get result from the HTTP request
const result = $json;
const success = result.status === 'complete' || result.cargoResult === 'OK' || result.gitResult?.includes('pushed');

if (success) {
  state.phases[phase].status = 'complete';
  state.phases[phase].result = result;
  state.phases[phase].completedAt = new Date().toISOString();

  // If this was mom-solver, also mark fdtd-python as needing run (they're parallel)
  if (phase === 'mom-solver' && state.phases['fdtd-python'].status === 'pending') {
    // fdtd will be triggered next
  }
} else {
  state.phases[phase].status = 'failed';
  state.phases[phase].attempts++;
  state.phases[phase].lastError = JSON.stringify(result).slice(0, 1000);
}

fs.writeFileSync(STATE_FILE, JSON.stringify(state, null, 2));

// Determine if we need hotfix
const needsHotfix = !success && state.phases[phase].attempts < state.maxRetries;

// Determine next action
let nextAction = 'continue';
if (!success && needsHotfix) nextAction = 'hotfix';
if (!success && !needsHotfix) nextAction = 'abort';

// Check if all phases complete
const allDone = Object.values(state.phases).every(p => p.status === 'complete');
if (allDone) nextAction = 'done';

return [{ json: { state, phase, success, nextAction, result } }];

const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const STATE_FILE = path.join(PROJECT, '.claude/em-pipeline-state.json');
const state = JSON.parse(fs.readFileSync(STATE_FILE, 'utf8'));

state.completedAt = new Date().toISOString();
state.status = 'COMPLETE';

const summary = Object.entries(state.phases).map(([phase, info]) => 
  `${phase}: ${info.status} (${info.attempts} attempts)`
).join('\n');

fs.writeFileSync(STATE_FILE, JSON.stringify(state, null, 2));

return [{ json: { status: 'PIPELINE COMPLETE', summary, state } }];

const state = $json.state;
const phase = $json.phase;
const rollbackInfo = state.initialCommit
  ? `Rollback available: git reset --hard ${state.initialCommit}`
  : 'No rollback commit saved';

return [{ json: {
  status: 'PIPELINE ABORTED',
  failedPhase: phase,
  rollbackInfo,
  state
} }];
